import React, { useEffect, useState } from 'react';
import ArticleCard from '../components/ArticleCard';
import { request } from '../utils/httpClient';
import config from '../config/config';

const HeadlinesPage = () => {
    const [activeCategory, setActiveCategory] = useState('All');
    const [articles, setArticles] = useState([]);

    // Updated categories to match Guardian sections backfilled
    const categories = ['All', 'World', 'Science', 'Technology', 'Sport', 'Business', 'Lifestyle', 'Culture', 'Environment'];

    useEffect(() => {
        let isMounted = true;

        async function fetchHeadlines() {
            setArticles([]); // Clear on switch
            try {
                // Pass category to API (if All, send nothing or handled by backend)
                const queryParam = activeCategory === 'All' ? '' : `?category=${activeCategory}`;
                const data = await request(`${config.api.endpoints.news}/headlines${queryParam}`);
                if (isMounted) {
                    const fetchedArticles = data.articles || [];
                    console.log("Fetched articles:", fetchedArticles.length);
                    // Map backend 'topic' to frontend 'category' expectation (just in case)
                    const mappedArticles = fetchedArticles.map(article => ({
                        ...article,
                        category: article.topic || 'General'
                    }));
                    setArticles(mappedArticles);
                }
            } catch (err) {
                console.error("Failed to fetch headlines:", err);
            }
        }

        fetchHeadlines();

        return () => {
            isMounted = false;
        };
    }, [activeCategory]); // Refetch when category changes

    // No client-side filtering needed if backend handles it
    const filteredArticles = articles;

    return (
        <div className="min-h-screen bg-cream-50 px-6 py-12">
            <div className="max-w-7xl mx-auto">
                <header className="mb-12 text-center">
                    <h1 className="font-serif text-6xl md:text-7xl font-black mb-4">HEADLINES</h1>
                    <p className="text-xl font-bold text-gray-500">Today's most important stories, curated for you.</p>
                </header>

                {/* Category Tabs */}
                <div className="flex overflow-x-auto pb-4 mb-8 gap-4 justify-start md:justify-center scrollbar-hide">
                    {categories.map((category) => (
                        <button
                            key={category}
                            onClick={() => setActiveCategory(category)}
                            className={`
                                whitespace-nowrap px-6 py-2 font-bold text-lg border-b-4 transition-all
                                ${activeCategory === category
                                    ? 'border-soft-blue-500 text-black'
                                    : 'border-transparent text-gray-400 hover:text-gray-600 hover:border-gray-200'}
                            `}
                        >
                            {category.toUpperCase()}
                        </button>
                    ))}
                </div>

                {/* Masonry Layout using CSS Columns */}
                <div className="columns-1 md:columns-2 lg:columns-3 gap-8 space-y-8">
                    {filteredArticles.map((article) => (
                        <div key={article.id} className="break-inside-avoid mb-8">
                            <ArticleCard
                                id={article.id}
                                title={article.title}
                                category={article.category}
                                imageUrl={article.image}   // <-- backend field
                                size="medium"              // you can decide how to size dynamically
                                article={article}
                            />
                        </div>
                    ))}
                </div>


                <div className="mt-20 text-center">
                    <button className="font-bold text-xl border-b-4 border-black pb-1 hover:text-soft-blue-600 hover:border-soft-blue-600 transition-colors">
                        LOAD MORE STORIES
                    </button>
                </div>
            </div>
        </div>
    );
};

export default HeadlinesPage;
